// And groups predicates with the AND operator between them.
func And(predicates ...predicate.TaskAttempt) predicate.TaskAttempt {
	return predicate.TaskAttempt(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
